<?php require_once __DIR__.'/../config/db.php';require_once __DIR__.'/../includes/csrf.php';if($_SERVER['REQUEST_METHOD']!=='POST'||!verify_csrf($_POST['csrf_token']??''))exit('Demande invalide.');if(!empty($_POST['website']))redirect('/');foreach(['car_id','pickup_city','pickup_location','pickup_date','return_date','full_name','phone'] as $f)if(trim($_POST[$f]??'')==='')exit('Champs obligatoires manquants.');if(!valid_date($_POST['pickup_date'])||!valid_date($_POST['return_date'])||$_POST['return_date']<$_POST['pickup_date'])exit('Dates invalides.');$st=$pdo->prepare('SELECT c.*,a.name agency_name,a.whatsapp_number FROM cars c JOIN agencies a ON a.id=c.agency_id WHERE c.id=:id LIMIT 1');$st->execute(['id'=>(int)$_POST['car_id']]);$car=$st->fetch();if(!$car)exit('Véhicule introuvable.');$in=$pdo->prepare('INSERT INTO leads (car_id,agency_id,full_name,phone,pickup_city,pickup_location,pickup_date,return_date,message,whatsapp_opened,status) VALUES (:car_id,:agency_id,:full_name,:phone,:pickup_city,:pickup_location,:pickup_date,:return_date,:message,0,:status)');$in->execute(['car_id'=>$car['id'],'agency_id'=>$car['agency_id'],'full_name'=>trim($_POST['full_name']),'phone'=>trim($_POST['phone']),'pickup_city'=>trim($_POST['pickup_city']),'pickup_location'=>trim($_POST['pickup_location']),'pickup_date'=>$_POST['pickup_date'],'return_date'=>$_POST['return_date'],'message'=>trim($_POST['message']??''),'status'=>'new']);$id=$pdo->lastInsertId();$msg='Bonjour '.$car['agency_name'].', je souhaite réserver le véhicule *'.$car['name'].'* du '.$_POST['pickup_date'].' au '.$_POST['return_date'].' (Prise en charge: '.trim($_POST['pickup_location']).'). Merci de me confirmer le tarif global et la disponibilité. Mon nom: '.trim($_POST['full_name']).'.';$pdo->prepare('UPDATE leads SET whatsapp_opened=1 WHERE id=:id')->execute(['id'=>$id]);redirect('https://wa.me/'.preg_replace('/\D+/','',$car['whatsapp_number']?:DEFAULT_WHATSAPP).'?text='.rawurlencode($msg));